#include<bits/stdc++.h>
using namespace std;

/*
Make a adjacency list from one digit to all the places
Since all the edges has cost = 1, run bfs from 1
Store the cost and print
Clear the adjacency list as we will not visit same digit twice
*/


const int N = 1e5 + 10;
const int INF = 1e9;

vector<int> adj[10];
vector<int> vis(N, 0);
vector<int> d(N, INF);

int n;
string s;

void bfs(int v) { 
    queue<int> q;
    q.push(v);

    d[v] = 0;

    while(!q.empty()) { 
        int u = q.front();
        q.pop();

        if(vis[u]) { 
            continue;
        }

        vis[u] = 1; 

        for(auto x: adj[s[u] - '0']) {
            q.push(x);
            d[x] = min(d[x], d[u] + 1);
        }   
        adj[s[u] - '0'].clear();
        if(u + 1 <= n - 1) { // Edge from index: i to i + 1
            q.push(u + 1);
            d[u + 1] = min(d[u + 1], d[u] + 1);
        }
        if(u - 1 >= 0) { // Edge from index: i to i - 1
            q.push(u - 1);
            d[u - 1] = min(d[u - 1], d[u] + 1);
        }
    }   
}

int main() {
    cin >> s;
    n = s.size();

    for(int i = 0; i < n; i++) {
        adj[s[i] - '0'].push_back(i); // adjacency list from digit
    }

    bfs(0);

    cout << d[n - 1] << "\n";
    return 0;
}

