#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>
#include <limits.h>

#define N 100010
#define INF 1000000000

int adj[10][N]; // Adjacency list for each digit, with a large enough size
int adj_size[10]; // Size of each adjacency list
bool vis[N];
int d[N];
char s[N];
int n;

void bfs(int v) {
    int queue[N];
    int front = 0, back = 0;

    queue[back++] = v;
    d[v] = 0;

    while (front < back) {
        int u = queue[front++];

        if (vis[u]) {
            continue;
        }

        vis[u] = true;

        int digit = s[u] - '0';

        // Traverse all adjacent nodes for the digit
        for (int i = 0; i < adj_size[digit]; i++) {
            int x = adj[digit][i];
            if (d[x] > d[u] + 1) {
                queue[back++] = x;
                d[x] = d[u] + 1;
            }
        }
        adj_size[digit] = 0; // Clear the adjacency list for the digit

        // Traverse adjacent nodes by index
        if (u + 1 < n) {
            if (d[u + 1] > d[u] + 1) {
                queue[back++] = u + 1;
                d[u + 1] = d[u] + 1;
            }
        }
        if (u - 1 >= 0) {
            if (d[u - 1] > d[u] + 1) {
                queue[back++] = u - 1;
                d[u - 1] = d[u] + 1;
            }
        }
    }
}

int main() {
    if (scanf("%s", s) != 1) {
        fprintf(stderr, "Failed to read input string\n");
        return 1;
    }
    n = strlen(s);

    for (int i = 0; i < n; i++) {
        int digit = s[i] - '0';
        if (digit >= 0 && digit < 10) {
            adj[digit][adj_size[digit]++] = i; // Add index i to the adjacency list of the digit
        }
    }

    for (int i = 0; i < n; i++) {
        d[i] = INF;
        vis[i] = false;
    }

    bfs(0);

    if (d[n - 1] == INF) {
        printf("-1\n");
    } else {
        printf("%d\n", d[n - 1]);
    }

    return 0;
}

