import java.util.*;

/*
Make a adjacency list from one digit to all the places
Since all the edges has cost = 1, run bfs from 1
Store the cost and print
Clear the adjacency list as we will not visit same digit twice
*/


class main {
    static int N = 100010;
    static int INF = 1000000000;
    static ArrayList<Integer>[] adj = new ArrayList[10];
    static int[] vis = new int[N];
    static int[] d = new int[N];
    static int n;
    static String s;

    public static void bfs(int v) {
        Queue<Integer> q = new LinkedList<>();
        q.add(v);

        d[v] = 0;

        while (!q.isEmpty()) {
            int u = q.poll();

            if (vis[u] != 0) {
                continue;
            }

            vis[u] = 1;

            for (int x : adj[s.charAt(u) - '0']) {
                q.add(x);
                d[x] = Math.min(d[x], d[u] + 1);
            }

            adj[s.charAt(u) - '0'].clear();

            if (u + 1 <= n - 1) {
                q.add(u + 1);
                d[u + 1] = Math.min(d[u + 1], d[u] + 1);
            }
            if (u - 1 >= 0) {
                q.add(u - 1);
                d[u - 1] = Math.min(d[u - 1], d[u] + 1);
            }
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        s = scanner.next();
        n = s.length();

        for (int i = 0; i < 10; i++) {
            adj[i] = new ArrayList<>();
        }

        for (int i = 0; i < n; i++) {
            adj[s.charAt(i) - '0'].add(i);
        }

        for (int i = 0; i < n; i++) {
            d[i] = INF;
        }

        bfs(0);

        System.out.println(d[n - 1]);
    }
}
